<script setup>
import { reactive, ref } from "@vue/reactivity";
import { nextTick } from "vue";
import { watch } from "@vue/runtime-core";
import { useVuelidate } from "@vuelidate/core";
import { required } from "@vuelidate/validators";
import Papa from "papaparse";
import useClipboard from "vue-clipboard3";
import Modal from "./Modal.vue";

const closeableModal = ref(false);
const errorModal = ref(false);

let form = reactive({
  divdend1_1: "",
  divdend1_2: "",
  divdend2_1: "",
  divdend2_2: "",
  divdend3_1: "",
  divdend3_2: "",
  eps_1: "",
  eps_2: "",
  shares_1: "",
  shares_2: "",
  de_1: "",
  de_2: "",
  roe1_1: "",
  roe1_2: "",
  roe2_1: "",
  roe2_2: "",
  bvps_1: "",
  bvps_2: "",
  fcf_1: "",
  fcf_2: "",
  net1_1: "",
  net1_2: "",
  net2_1: "",
  net2_2: "",
  ic1_1: "",
  ic1_2: "",
  ic2_1: "",
  ic2_2: "",
  total: 0,
});

let divdend1Points = ref(0);
let divdend2Points = ref(0);
let divdend3Points = ref(0);
let epsPoints = ref(0);
let sharesPoints = ref(0);
let dePoints = ref(0);
let roe1Points = ref(0);
let roe2Points = ref(0);
let bvpsPoints = ref(0);
let fcfPoints = ref(0);
let net1Points = ref(0);
let net2Points = ref(0);
let ic1Points = ref(0);
let ic2Points = ref(0);
let total = ref(0);

// Divdend
let isShowDividendUrl = ref(false);
watch([() => form.divdend1_1, () => form.divdend2_1], (newValues) => {
  if (newValues.some((value) => value)) {
    isNoDivdend.value = false;
    isShowDividendUrl.value = true;
  } else {
    isShowDividendUrl.value = false;
  }
});

watch(
  [() => form.divdend1_1, () => form.divdend2_1, () => form.divdend3_1],
  (newValues) => {
    console.log(newValues);
    if (newValues.every((value) => value === false)) {
      isNoDivdend.value = true;
      isShowDividendUrl.value = false;
    }
  }
);

watch(
  () => form.divdend1_1,
  (newValue) => {
    if (newValue) {
      form.divdend2_2 = true;
      form.divdend2_1 = false;
      divdend2Points.value = 0;
    }
  }
);

watch(
  () => form.divdend2_1,
  (newValue) => {
    if (newValue) {
      form.divdend1_2 = true;
      form.divdend1_1 = false;
      divdend1Points.value = 0;
    }
  }
);
// ROE
watch(
  () => form.roe1_1,
  (newValue) => {
    if (newValue) {
      form.roe2_2 = true;
      form.roe2_1 = false;
      roe2Points.value = 0;
    }
  }
);
watch(
  () => form.roe2_1,
  (newValue) => {
    if (newValue) {
      form.roe1_2 = true;
      form.roe1_1 = false;
      roe1Points.value = 0;
    }
  }
);
// IC
watch(
  () => form.ic1_1,
  (newValue) => {
    if (newValue) {
      form.ic2_2 = true;
      form.ic2_1 = false;
      ic2Points.value = 0;
    }
  }
);
watch(
  () => form.ic2_1,
