function isLetterOrDot(e) {
  // 獲取字元
  let char = String.fromCharCode(e.keyCode);
  // 正則表達式，只允許英文字母和點號
  const regex = /^[a-zA-Z.]*$/;
  if (regex.test(char)) {
    return true;
  } else {
    // 如果不匹配，不添加到input框
    e.preventDefault();
  }
}

